import pytestfrom backend.app.models.user import Userfrom backend.app.services.user import UserServicefrom sqlalchemy.orm import Sessionfrom sqlalchemy import select@pytest.fixturedef user_admin(session: Session):    service = UserService(session)    user = service.add_user(        name="Kuka",        email="kuka@kuka.com",        password="password",        role="ADMIN"    )    return user@pytest.fixturedef user_one(session: Session):    service = UserService(session)    user = service.add_user(        name="Test User",        email="testuser@gmail.com",        password="password",        role="USER"    )    return userdef test_add_user(session: Session):    service = UserService(session)    users = session.scalars(select(User)).all()    assert users == []    user = service.add_user(        name="Test User",        email="testuser@gmail.com",        password="password",        role="USER"    )    result = session.scalars(        select(User)        .where(User.id == user.id)    ).one_or_none()    assert result == userdef test_add_user_duplicate_email(session: Session, user_one: User):    service = UserService(session)    with pytest.raises(ValueError, match="User with this email already exists"):        service.add_user(            name="Test User2",            email="testuser@gmail.com",            password="password",            role="USER"        )def test_get_user_by_email(session:Session, user_one: User):    service = UserService(session)    user_by_email = service.get_user_by_email(user_one.email)    assert user_by_email == user_onedef test_get_user_by_email_not_found(session:Session, user_one: User):    service = UserService(session)    with pytest.raises(ValueError, match="User not found"):        service.get_user_by_email("nonexistent@gmail.com")